101→          {t("newlineHint")}
102→        </span>
103→      </>
104→    );
105→  }
106→
107→  const hasNewlines = label.includes("\n");
108→
109→  return (
110→    <span
111→      className="node-label-text select-none max-w-full w-full"
112→      style={textStyle}
113→      onDoubleClick={() => !isLocked && setEditing(true)}
114→    >
115→      {hasNewlines
116→        ? label.split("\n").map((line, i) => (
117→            <span key={i}>
118→              {i > 0 && <br />}
119→              {line}
120→            </span>
121→          ))
122→        : label}
123→    </span>
124→  );
125→}
