196→// ---- Flow order computation ----
197→
198→/** Topological sort via BFS from root nodes (no incoming edges).
199→ *  Interleaves nodes and their outgoing edges in traversal order. */
200→function buildFlowOrder(nodes: FlowNode[], edges: FlowEdge[]): BulkEditItem[] {
201→  const nodeMap = new Map(nodes.map((n) => [n.id, n]));
202→  const incomingCount = new Map<string, number>();
203→  const outgoingEdges = new Map<string, FlowEdge[]>();
204→
205→  for (const n of nodes) {
206→    incomingCount.set(n.id, 0);
207→    outgoingEdges.set(n.id, []);
208→  }
209→  for (const e of edges) {
210→    incomingCount.set(e.target, (incomingCount.get(e.target) ?? 0) + 1);
211→    outgoingEdges.get(e.source)?.push(e);
212→  }
213→
214→  // Start from nodes with no incoming edges
215→  const queue: string[] = [];
216→  for (const n of nodes) {
217→    if ((incomingCount.get(n.id) ?? 0) === 0) {
218→      queue.push(n.id);
219→    }
220→  }
221→
222→  const visited = new Set<string>();
223→  const visitedEdges = new Set<string>();
224→  const items: BulkEditItem[] = [];
225→
226→  while (queue.length > 0) {
227→    const id = queue.shift()!;
228→    if (visited.has(id)) continue;
229→    visited.add(id);
230→
231→    const node = nodeMap.get(id);
232→    if (node) items.push({ kind: "node", node });
233→
234→    for (const edge of outgoingEdges.get(id) ?? []) {
235→      if (visitedEdges.has(edge.id)) continue;
236→      visitedEdges.add(edge.id);
237→      items.push({ kind: "edge", edge });
238→
239→      if (!visited.has(edge.target)) {
240→        // Decrement and enqueue if all incoming visited
241→        const remaining = (incomingCount.get(edge.target) ?? 1) - 1;
242→        incomingCount.set(edge.target, remaining);
243→        if (remaining <= 0) {
244→          queue.push(edge.target);
245→        }
246→      }
247→    }
248→  }
249→
250→  // Add any remaining unvisited nodes (disconnected or in cycles)
251→  for (const n of nodes) {
252→    if (!visited.has(n.id)) {
253→      items.push({ kind: "node", node: n });
254→      for (const edge of outgoingEdges.get(n.id) ?? []) {
255→        if (!visitedEdges.has(edge.id)) {
256→          visitedEdges.add(edge.id);
257→          items.push({ kind: "edge", edge });
258→        }
259→      }
260→    }
261→  }
262→
263→  // Add any remaining edges not yet included
264→  for (const e of edges) {
265→    if (!visitedEdges.has(e.id)) {
266→      items.push({ kind: "edge", edge: e });
267→    }
268→  }
269→
270→  return items;
271→}
272→
273→/** Sort nodes by canvas position: TD → y-primary then x, LR → x-primary then y */
274→function sortNodesByPosition(nodes: FlowNode[], direction: FlowDirection): FlowNode[] {
275→  return [...nodes].sort((a, b) => {
276→    if (direction === "LR") {
277→      return a.position.x - b.position.x || a.position.y - b.position.y;
278→    }
279→    return a.position.y - b.position.y || a.position.x - b.position.x;
280→  });
281→}
282→
283→/** Sort edges by source node position, then target node position */
284→function sortEdgesByPosition(edges: FlowEdge[], nodes: FlowNode[], direction: FlowDirection): FlowEdge[] {
285→  const posMap = new Map(nodes.map((n) => [n.id, n.position]));
286→  const zero = { x: 0, y: 0 };
287→  return [...edges].sort((a, b) => {
288→    const srcA = posMap.get(a.source) ?? zero;
289→    const srcB = posMap.get(b.source) ?? zero;
290→    const tgtA = posMap.get(a.target) ?? zero;
291→    const tgtB = posMap.get(b.target) ?? zero;
292→    if (direction === "LR") {
293→      return srcA.x - srcB.x || srcA.y - srcB.y || tgtA.x - tgtB.x || tgtA.y - tgtB.y;
294→    }
295→    return srcA.y - srcB.y || srcA.x - srcB.x || tgtA.y - tgtB.y || tgtA.x - tgtB.x;
296→  });
297→}
