 43→// Module-level state for reconnection: fixed endpoint position
 44→let reconnectFixedEnd: { x: number; y: number; position: import("@xyflow/react").Position } | null = null;
 45→
 46→function inferTargetPosition(sourceX: number, sourceY: number, targetX: number, targetY: number): Position {
 47→  const dx = targetX - sourceX;
 48→  const dy = targetY - sourceY;
 49→  if (Math.abs(dx) > Math.abs(dy)) {
 50→    return dx > 0 ? Position.Left : Position.Right;
 51→  }
 52→  return dy > 0 ? Position.Top : Position.Bottom;
 53→}
