 55→function ReconnectConnectionLine({ fromX, fromY, toX, toY, fromPosition, toPosition }: ConnectionLineComponentProps<FlowNode>) {
 56→  let startX: number, startY: number, endX: number, endY: number;
 57→  let startPos = fromPosition;
 58→  let endPos = toPosition;
 59→
 60→  if (reconnectFixedEnd) {
 61→    // During reconnection: draw from fixed end to cursor
 62→    startX = reconnectFixedEnd.x;
 63→    startY = reconnectFixedEnd.y;
 64→    startPos = reconnectFixedEnd.position;
 65→    endX = toX;
 66→    endY = toY;
 67→    // Infer target position from direction so bezier doesn't overshoot cursor
 68→    endPos = inferTargetPosition(startX, startY, endX, endY);
 69→  } else {
 70→    // Normal connection: draw from drag origin to cursor
 71→    startX = fromX;
 72→    startY = fromY;
 73→    endX = toX;
 74→    endY = toY;
 75→    endPos = inferTargetPosition(startX, startY, endX, endY);
 76→  }
 77→
 78→  const [path] = getBezierPath({
 79→    sourceX: startX,
 80→    sourceY: startY,
 81→    sourcePosition: startPos,
 82→    targetX: endX,
 83→    targetY: endY,
 84→    targetPosition: endPos,
 85→  });
 86→
 87→  return (
 88→    <g>
 89→      <path d={path} fill="none" stroke="var(--primary)" strokeWidth={2} strokeDasharray="6 3" />
 90→    </g>
 91→  );
 92→}
