202→// ---- Flow order computation ----
203→
204→/** Topological sort via BFS from root nodes (no incoming edges).
205→ *  Interleaves nodes and their outgoing edges in traversal order. */
206→function buildFlowOrder(nodes: FlowNode[], edges: FlowEdge[]): BulkEditItem[] {
207→  const nodeMap = new Map(nodes.map((n) => [n.id, n]));
208→  const incomingCount = new Map<string, number>();
209→  const outgoingEdges = new Map<string, FlowEdge[]>();
210→
211→  for (const n of nodes) {
212→    incomingCount.set(n.id, 0);
213→    outgoingEdges.set(n.id, []);
214→  }
215→  for (const e of edges) {
216→    incomingCount.set(e.target, (incomingCount.get(e.target) ?? 0) + 1);
217→    outgoingEdges.get(e.source)?.push(e);
218→  }
219→
220→  // Start from nodes with no incoming edges
221→  const queue: string[] = [];
222→  for (const n of nodes) {
223→    if ((incomingCount.get(n.id) ?? 0) === 0) {
224→      queue.push(n.id);
225→    }
226→  }
227→
228→  const visited = new Set<string>();
229→  const visitedEdges = new Set<string>();
230→  const items: BulkEditItem[] = [];
231→
232→  while (queue.length > 0) {
233→    const id = queue.shift()!;
234→    if (visited.has(id)) continue;
235→    visited.add(id);
236→
237→    const node = nodeMap.get(id);
238→    if (node) items.push({ kind: "node", node });
239→
240→    for (const edge of outgoingEdges.get(id) ?? []) {
241→      if (visitedEdges.has(edge.id)) continue;
242→      visitedEdges.add(edge.id);
243→      items.push({ kind: "edge", edge });
244→
245→      if (!visited.has(edge.target)) {
246→        // Decrement and enqueue if all incoming visited
247→        const remaining = (incomingCount.get(edge.target) ?? 1) - 1;
248→        incomingCount.set(edge.target, remaining);
249→        if (remaining <= 0) {
250→          queue.push(edge.target);
251→        }
252→      }
253→    }
254→  }
255→
256→  // Add any remaining unvisited nodes (disconnected or in cycles)
257→  for (const n of nodes) {
258→    if (!visited.has(n.id)) {
259→      items.push({ kind: "node", node: n });
260→      for (const edge of outgoingEdges.get(n.id) ?? []) {
261→        if (!visitedEdges.has(edge.id)) {
262→          visitedEdges.add(edge.id);
263→          items.push({ kind: "edge", edge });
264→        }
265→      }
266→    }
267→  }
268→
269→  // Add any remaining edges not yet included
270→  for (const e of edges) {
271→    if (!visitedEdges.has(e.id)) {
272→      items.push({ kind: "edge", edge: e });
273→    }
274→  }
275→
276→  return items;
277→}
278→
279→/** Sort nodes by canvas position: TD → y-primary then x, LR → x-primary then y */
280→function sortNodesByPosition(nodes: FlowNode[], direction: FlowDirection): FlowNode[] {
281→  return [...nodes].sort((a, b) => {
282→    if (direction === "LR") {
283→      return a.position.x - b.position.x || a.position.y - b.position.y;
284→    }
285→    return a.position.y - b.position.y || a.position.x - b.position.x;
286→  });
287→}
288→
289→/** Sort edges by source node position, then target node position */
290→function sortEdgesByPosition(edges: FlowEdge[], nodes: FlowNode[], direction: FlowDirection): FlowEdge[] {
291→  const posMap = new Map(nodes.map((n) => [n.id, n.position]));
292→  const zero = { x: 0, y: 0 };
293→  return [...edges].sort((a, b) => {
294→    const srcA = posMap.get(a.source) ?? zero;
295→    const srcB = posMap.get(b.source) ?? zero;
296→    const tgtA = posMap.get(a.target) ?? zero;
297→    const tgtB = posMap.get(b.target) ?? zero;
298→    if (direction === "LR") {
299→      return srcA.x - srcB.x || srcA.y - srcB.y || tgtA.x - tgtB.x || tgtA.y - tgtB.y;
300→    }
301→    return srcA.y - srcB.y || srcA.x - srcB.x || tgtA.y - tgtB.y || tgtA.x - tgtB.x;
302→  });
303→}
