307→export const BulkEditTable = memo(function BulkEditTable({
308→  onFocusNode,
309→  onFocusEdge,
310→  highlightId,
311→  selectedIds,
312→}: BulkEditTableProps) {
313→  const nodes = useFlowStore((s) => s.nodes);
314→  const edges = useFlowStore((s) => s.edges);
315→  const updateNodeLabel = useFlowStore((s) => s.updateNodeLabel);
316→  const updateEdgeLabel = useFlowStore((s) => s.updateEdgeLabel);
317→  const updateComponentInstanceName = useFlowStore(
318→    (s) => s.updateComponentInstanceName
319→  );
320→  const direction = useFlowStore((s) => s.direction);
321→  const { t } = useLocale();
322→
323→  const [viewMode, setViewMode] = useState<ViewMode>("category");
324→  const [searchText, setSearchText] = useState("");
325→  // Unified filter: "" = all, "shape:rectangle" = node shape, "edge:bezier" = edge type
326→  const [filter, setFilter] = useState("");
327→  const [autoExpand, setAutoExpand] = useState(true);
328→
329→  const shapeFilter = filter.startsWith("shape:") ? filter.slice(6) as NodeShape : "";
330→  const edgeTypeFilter = filter.startsWith("edge:") ? filter.slice(5) as EdgeType : "";
331→
332→  // Canvas multi-selection override
333→  const selectedIdsSet = useMemo(() => new Set(selectedIds), [selectedIds]);
334→  const hasSelection = selectedIdsSet.size > 0;
335→
336→  const editableNodes = useMemo(
337→    () => nodes.filter((n) => !n.data.componentParentId && !n.data.isLocked),
338→    [nodes]
339→  );
340→  const editableEdges = useMemo(
341→    () => edges.filter((e) => !e.data?.isBridgeEdge),
342→    [edges]
343→  );
344→
345→  // Apply text search filter
346→  const searchLower = searchText.toLowerCase();
347→
348→  const filteredNodes = useMemo(() => {
349→    // Canvas multi-selection overrides all filters
350→    if (hasSelection) {
351→      return editableNodes.filter((n) => selectedIdsSet.has(n.id));
352→    }
353→    // Edge type filter active → hide all nodes
354→    if (edgeTypeFilter) return [];
355→    let result = editableNodes;
356→    if (searchText) {
357→      result = result.filter((n) => {
358→        const label = n.data.componentInstanceName ?? n.data.label;
359→        return label.toLowerCase().includes(searchLower);
360→      });
361→    }
362→    if (shapeFilter) {
363→      result = result.filter((n) => n.data.shape === shapeFilter);
364→    }
365→    return result;
366→  }, [editableNodes, searchLower, searchText, shapeFilter, edgeTypeFilter, hasSelection, selectedIdsSet]);
367→
368→  const filteredEdges = useMemo(() => {
369→    // Canvas multi-selection → show edges connected to selected nodes
370→    if (hasSelection) {
371→      return editableEdges.filter(
372→        (e) => selectedIdsSet.has(e.source) || selectedIdsSet.has(e.target)
373→      );
374→    }
375→    // Shape filter active → only edges connected to matching nodes
376→    if (shapeFilter) {
377→      const matchingNodeIds = new Set(filteredNodes.map((n) => n.id));
378→      let result = editableEdges.filter(
379→        (e) => matchingNodeIds.has(e.source) || matchingNodeIds.has(e.target)
380→      );
381→      if (searchText) {
382→        result = result.filter((e) =>
383→          (e.data?.label ?? "").toLowerCase().includes(searchLower)
384→        );
385→      }
386→      return result;
387→    }
388→    let result = editableEdges;
389→    if (edgeTypeFilter) {
390→      result = result.filter(
391→        (e) => (e.data?.edgeType ?? DEFAULT_EDGE_TYPE) === edgeTypeFilter
392→      );
393→    }
394→    if (searchText) {
395→      result = result.filter((e) =>
396→        (e.data?.label ?? "").toLowerCase().includes(searchLower)
397→      );
398→    }
399→    return result;
400→  }, [editableEdges, shapeFilter, filteredNodes, edgeTypeFilter, searchLower, searchText, hasSelection, selectedIdsSet]);
401→
402→  // Build items list based on view mode
403→  const items = useMemo((): BulkEditItem[] => {
404→    if (viewMode === "flow") {
405→      return buildFlowOrder(filteredNodes, filteredEdges);
406→    }
407→    // Category mode: nodes sorted by canvas position, edges sorted by source position
408→    const sortedNodes = sortNodesByPosition(filteredNodes, direction);
409→    const sortedEdges = sortEdgesByPosition(filteredEdges, editableNodes, direction);
410→    const result: BulkEditItem[] = [];
411→    result.push({ kind: "section", label: t("nodes"), sectionType: "nodes" });
412→    for (const node of sortedNodes) {
413→      result.push({ kind: "node", node });
414→    }
415→    result.push({ kind: "section", label: t("bulkEditEdges"), sectionType: "edges" });
416→    for (const edge of sortedEdges) {
417→      result.push({ kind: "edge", edge });
418→    }
419→    return result;
420→  }, [viewMode, filteredNodes, filteredEdges, editableNodes, direction, t]);
421→
422→  // Refs for keyboard navigation
423→  const inputRefsRef = useRef<(HTMLTextAreaElement | null)[]>([]);
424→
425→  // Use useRef to avoid stale closure in handleNodeLabelChange
426→  const nodesRef = useRef(nodes);
427→  nodesRef.current = nodes;
428→  const autoExpandRef = useRef(autoExpand);
429→  autoExpandRef.current = autoExpand;
430→
431→  const handleKeyDown = useCallback(
432→    (e: React.KeyboardEvent, index: number) => {
433→      if (e.key === "Enter" && e.shiftKey) {
434→        // Allow newline insertion (default textarea behavior)
435→        return;
436→      }
437→      if (e.key === "Enter" || (e.key === "Tab" && !e.shiftKey)) {
438→        e.preventDefault();
439→        const next = index + 1;
440→        if (inputRefsRef.current[next]) {
441→          inputRefsRef.current[next]?.focus();
442→        }
443→      } else if (e.key === "Tab" && e.shiftKey) {
444→        e.preventDefault();
445→        const prev = index - 1;
446→        if (prev >= 0) {
447→          inputRefsRef.current[prev]?.focus();
448→        }
449→      }
450→    },
451→    []
452→  );
453→
454→  const handleNodeLabelChange = useCallback(
455→    (id: string, label: string) => {
456→      const node = nodesRef.current.find((n) => n.id === id);
457→      if (node?.data.componentDefinitionId) {
458→        updateComponentInstanceName(id, label);
459→      } else {
460→        const resizeMode = autoExpandRef.current ? "both" : "none";
461→        updateNodeLabel(id, label, resizeMode);
462→      }
463→    },
464→    [updateNodeLabel, updateComponentInstanceName]
465→  );
466→
467→  const handleEdgeLabelChange = useCallback(
468→    (id: string, label: string) => {
469→      updateEdgeLabel(id, label);
470→    },
471→    [updateEdgeLabel]
472→  );
473→
474→  // Compute input index (skip section headers)
475→  let inputIndex = 0;
476→
477→  return (
478→    <div className="h-full flex flex-col bg-background">
479→      {/* Toolbar: search + shape filter + view mode */}
480→      <div className="px-3 pt-3 pb-2 space-y-2 border-b border-border shrink-0">
481→        {/* Search with clear button */}
482→        <div className="relative">
483→          <Search
484→            size={14}
485→            className="absolute left-2 top-1/2 -translate-y-1/2 text-muted-foreground"
486→          />
487→          <Input
488→            className="h-7 text-sm pl-7 pr-7"
489→            placeholder={t("bulkEditSearch")}
490→            value={searchText}
491→            onChange={(e) => setSearchText(e.target.value)}
492→          />
493→          {searchText && (
494→            <button
495→              className="absolute right-1.5 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"
496→              onClick={() => setSearchText("")}
497→            >
498→              <X size={14} />
499→            </button>
500→          )}
501→        </div>
502→
503→        <div className="flex items-center gap-2">
504→          {/* Unified filter dropdown */}
505→          <DropdownMenu>
506→            <DropdownMenuTrigger asChild>
507→              <Button
508→                variant="outline"
509→                size="sm"
510→                className="h-7 text-xs gap-1 flex-1 min-w-0 justify-between"
511→              >
512→                <span className="flex items-center gap-1.5 truncate">
513→                  {shapeFilter ? (
514→                    <>
515→                      <BulkEditNodeIcon shape={shapeFilter} />
516→                      {t(SHAPE_FILTER_OPTIONS.find((o) => o.value === shapeFilter)?.key ?? "rectangle")}
517→                    </>
518→                  ) : edgeTypeFilter ? (
519→                    <>
520→                      <BulkEditEdgeIcon />
521→                      {t(EDGE_FILTER_OPTIONS.find((o) => o.value === edgeTypeFilter)?.key ?? "bezier")}
522→                    </>
523→                  ) : (
524→                    t("all")
525→                  )}
526→                </span>
527→                <ChevronDown size={12} className="shrink-0 text-muted-foreground" />
528→              </Button>
529→            </DropdownMenuTrigger>
530→            <DropdownMenuContent align="start" className="max-h-72 overflow-y-auto">
531→              <DropdownMenuItem onClick={() => setFilter("")}>
532→                {t("all")}
533→              </DropdownMenuItem>
534→              <DropdownMenuSeparator />
535→              <DropdownMenuLabel className="text-[10px]">{t("nodes")}</DropdownMenuLabel>
536→              {SHAPE_FILTER_OPTIONS.map(({ value, key }) => (
537→                <DropdownMenuItem
538→                  key={value}
539→                  onClick={() => setFilter(`shape:${value}`)}
540→                  className="gap-2"
541→                >
542→                  <BulkEditNodeIcon shape={value} />
543→                  <span>{t(key)}</span>
544→                </DropdownMenuItem>
545→              ))}
546→              <DropdownMenuSeparator />
547→              <DropdownMenuLabel className="text-[10px]">{t("bulkEditEdges")}</DropdownMenuLabel>
548→              {EDGE_FILTER_OPTIONS.map(({ value, key }) => (
549→                <DropdownMenuItem
550→                  key={value}
551→                  onClick={() => setFilter(`edge:${value}`)}
552→                  className="gap-2"
553→                >
554→                  <BulkEditEdgeIcon />
555→                  <span>{t(key)}</span>
556→                </DropdownMenuItem>
557→              ))}
558→            </DropdownMenuContent>
559→          </DropdownMenu>
560→
561→          {/* View mode toggle */}
562→          <ToggleGroup
563→            type="single"
564→            value={viewMode}
565→            onValueChange={(val) => {
566→              if (val) setViewMode(val as ViewMode);
567→            }}
568→            className="h-7 shrink-0"
569→          >
570→            <ToggleGroupItem value="category" className="h-7 px-2 text-[10px]">
571→              {t("bulkEditViewCategory")}
572→            </ToggleGroupItem>
573→            <ToggleGroupItem value="flow" className="h-7 px-2 text-[10px]">
574→              {t("bulkEditViewFlow")}
575→            </ToggleGroupItem>
576→          </ToggleGroup>
577→        </div>
578→      </div>
579→
580→      {/* Items list */}
581→      <ScrollArea className="flex-1">
582→        <div className="pt-2 pb-3 px-3 space-y-1">
583→          {items.map((item) => {
584→            if (item.kind === "section") {
