589→                >
590→                  {item.label}
591→                  {item.sectionType === "nodes" && (
592→                    <Tooltip>
593→                      <TooltipTrigger asChild>
594→                        <button
595→                          className={`inline-flex items-center justify-center rounded-md p-1.5 transition-colors ${
596→                            autoExpand
597→                              ? "text-primary bg-primary/15 hover:bg-primary/25"
598→                              : "text-muted-foreground hover:text-foreground hover:bg-muted"
599→                          }`}
600→                          onClick={() => setAutoExpand((v) => !v)}
601→                        >
