  1→"use client";
  2→
  3→import { useCallback, useRef, useEffect } from "react";
  4→import { useStoreApi } from "@xyflow/react";
  5→import { getNodesInside } from "@xyflow/system";
  6→import { perfStart, perfEnd, perfCount } from "@/lib/perf";
  7→import type {
  8→  Node,
  9→  Edge,
 10→  NodeMouseHandler,
 11→  EdgeMouseHandler,
 12→  NodeChange,
 13→  EdgeChange,
 14→} from "@xyflow/react";
 15→
 16→// ---------------------------------------------------------------------------
 17→// Types
 18→// ---------------------------------------------------------------------------
 19→
 20→type EdgeInfo = { id: string; source: string; target: string; data?: { isBridgeEdge?: boolean } };
 21→
 22→export interface UseCtrlSelectionOptions {
 23→  /** Read current selected IDs */
 24→  getSelectedIds: () => Set<string>;
 25→  /** Apply new selected IDs */
 26→  setSelectedIds: (ids: Set<string>) => void;
 27→
 28→  /** Provide edges — used for drag‐selection "both‐endpoints" rule and Ctrl+A */
 29→  getEdges?: () => readonly EdgeInfo[];
 30→
 31→  /** Return all selectable IDs for Ctrl+A. Omit to skip Ctrl+A handling. */
 32→  getAllSelectableIds?: () => Set<string>;
 33→
 34→  /** Currently highlighted ID (BulkEdit: include in starting set on Ctrl+click) */
 35→  highlightId?: string | null;
 36→
 37→  /** Called on normal (non-Ctrl) node click. If omitted, ReactFlow default applies. */
 38→  onNormalNodeClick?: (nodeId: string) => void;
 39→  /** Called on normal (non-Ctrl) edge click. If omitted, ReactFlow default applies. */
 40→  onNormalEdgeClick?: (edgeId: string) => void;
 41→  /** Called on pane click. If omitted, ReactFlow default applies. */
 42→  onNormalPaneClick?: () => void;
 43→}
 44→
 45→// ---------------------------------------------------------------------------
 46→// Helpers (module-level, no allocation per render)
 47→// ---------------------------------------------------------------------------
 48→
 49→/** Select edges whose BOTH source and target are in `ids`; deselect the rest. */
 50→function syncEdgeSelection(ids: Set<string>, edges: readonly EdgeInfo[]) {
 51→  for (const e of edges) {
 52→    if (e.data?.isBridgeEdge) continue;
 53→    if (ids.has(e.source) && ids.has(e.target)) ids.add(e.id);
 54→    else ids.delete(e.id);
 55→  }
 56→}
 57→
 58→/** Returns true if two Sets contain the same elements. */
 59→function setsEqual(a: Set<string>, b: Set<string>): boolean {
 60→  if (a.size !== b.size) return false;
 61→  for (const id of a) {
 62→    if (!b.has(id)) return false;
 63→  }
 64→  return true;
 65→}
 66→
 67→/** Build a Set of edge IDs for filtering node IDs from a mixed set. */
 68→function buildEdgeIdSet(edges: readonly { id: string }[]): Set<string> {
 69→  const s = new Set<string>();
 70→  for (const e of edges) s.add(e.id);
 71→  return s;
 72→}
 73→
 74→/** Extract only node IDs from a mixed selection set. */
 75→function extractNodeIds(ids: Set<string>, edgeIdSet: Set<string>): Set<string> {
 76→  const result = new Set<string>();
 77→  for (const id of ids) {
 78→    if (!edgeIdSet.has(id)) result.add(id);
 79→  }
 80→  return result;
 81→}
 82→
 83→/** Symmetric difference (XOR) of two sets. */
 84→function symmetricDifference(a: Set<string>, b: Set<string>): Set<string> {
 85→  const result = new Set<string>();
 86→  for (const id of a) { if (!b.has(id)) result.add(id); }
 87→  for (const id of b) { if (!a.has(id)) result.add(id); }
 88→  return result;
 89→}
 90→
 91→/** Apply `setSelectedIds` only when the selection actually changed. */
 92→function applyIfChanged(
 93→  next: Set<string>,
 94→  getSelectedIds: () => Set<string>,
 95→  setSelectedIds: (ids: Set<string>) => void,
 96→) {
 97→  if (!setsEqual(next, getSelectedIds())) {
 98→    setSelectedIds(next);
 99→  }
100→}

