  highlightId,
  onNodeClick,
  onEdgeClick,
  onSelectionChange,
  onPaneClick,
  onExit,
}: BulkEditCanvasProps) {
  return (
    <ReactFlowProvider>
      <BulkEditCanvasInner
        focusTarget={focusTarget}
        highlightId={highlightId}
        onNodeClick={onNodeClick}
        onEdgeClick={onEdgeClick}
        onSelectionChange={onSelectionChange}
        onPaneClick={onPaneClick}
        onExit={onExit}
      />
    </ReactFlowProvider>
  );
});

